package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.io.Writer;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonWriterTest {

  private JsonWriter jsonWriter;
  private Writer mockWriter;

  @BeforeEach
  public void setUp() {
    mockWriter = new StringWriter();
    jsonWriter = new JsonWriter(mockWriter);
  }

  @Test
  public void testSetHtmlSafe_setsHtmlSafeTrue() {
    jsonWriter.setHtmlSafe(true);
    assertTrue(jsonWriter.isHtmlSafe());
  }

  @Test
  public void testSetHtmlSafe_setsHtmlSafeFalse() {
    jsonWriter.setHtmlSafe(false);
    assertFalse(jsonWriter.isHtmlSafe());
  }

  @Test
  public void testSetHtmlSafe_reflectionInvocation() throws Exception {
    Method setHtmlSafeMethod = JsonWriter.class.getDeclaredMethod("setHtmlSafe", boolean.class);
    setHtmlSafeMethod.setAccessible(true);

    // Invoke with true
    setHtmlSafeMethod.invoke(jsonWriter, true);
    Method isHtmlSafeMethod = JsonWriter.class.getDeclaredMethod("isHtmlSafe");
    isHtmlSafeMethod.setAccessible(true);
    boolean resultTrue = (boolean) isHtmlSafeMethod.invoke(jsonWriter);
    assertTrue(resultTrue);

    // Invoke with false
    setHtmlSafeMethod.invoke(jsonWriter, false);
    boolean resultFalse = (boolean) isHtmlSafeMethod.invoke(jsonWriter);
    assertFalse(resultFalse);
  }
}
